const fs = await import('fs');
const path = await import('path');

const TOKEN = process.env.GITHUB_PERSONAL_ACCESS_TOKEN2;
const REPO = "donatelloroberto/Asset-Extractor-web";
const BASE = "https://api.github.com";

const headers = {
  Authorization: `Bearer ${TOKEN}`,
  Accept: "application/vnd.github+json",
  "Content-Type": "application/json",
  "X-GitHub-Api-Version": "2022-11-28",
};

async function getFileSha(filePath) {
  const res = await fetch(`${BASE}/repos/${REPO}/contents/${filePath}`, { headers });
  if (res.status === 404) return null;
  const data = await res.json();
  return data.sha;
}

async function upsertFile(filePath, localPath) {
  const content = fs.readFileSync(localPath, 'utf-8');
  const encoded = Buffer.from(content).toString('base64');
  const sha = await getFileSha(filePath);
  const body = {
    message: `Add Deploy page with Vercel + Render build/start commands`,
    content: encoded,
    ...(sha ? { sha } : {}),
  };
  const res = await fetch(`${BASE}/repos/${REPO}/contents/${filePath}`, {
    method: "PUT",
    headers,
    body: JSON.stringify(body),
  });
  const data = await res.json();
  console.log(`${filePath}: ${res.status} ${data.commit?.sha?.slice(0,7) ?? data.message}`);
}

const files = [
  ["client/src/pages/deploy.tsx", "/home/runner/workspace/client/src/pages/deploy.tsx"],
  ["client/src/App.tsx", "/home/runner/workspace/client/src/App.tsx"],
  ["client/src/components/navbar.tsx", "/home/runner/workspace/client/src/components/navbar.tsx"],
];

for (const [repo, local] of files) {
  await upsertFile(repo, local);
}

