    28→async function resolveWithCache(url: string, referer?: string): Promise<ResolvedStream> {
    29→  const cacheKey = `resolved:${url}`;
    30→  const cached = getCached<ResolvedStream>("stream", cacheKey);
    31→  if (cached) return cached;
    32→
    33→  const resolved = await resolveMedia(url, referer);
    34→  setCached("stream", cacheKey, resolved);
