    38→export async function mapStreamsForStremio(extracted: ExtractedStream[], baseUrl?: string): Promise<StremioStream[]> {
    39→  const RESOLVE_TIMEOUT = 8000;
    40→
    41→  const mapped = await Promise.all(extracted.map(async (s): Promise<StremioStream | null> => {
    42→    if (s.externalUrl) {
    43→      return {
    44→        name: s.name,
    45→        title: s.title || s.name,
    46→        externalUrl: s.externalUrl,
    47→        behaviorHints: { notWebReady: false },
    48→      };
    49→    }
    50→
    51→    if (!s.url) return null;
    52→
    53→    let resolved: ResolvedStream;
    54→    try {
    55→      resolved = await Promise.race([
    56→        resolveWithCache(s.url, s.referer),
    57→        new Promise<ResolvedStream>((_, reject) =>
    58→          setTimeout(() => reject(new Error("resolve timeout")), RESOLVE_TIMEOUT)
    59→        ),
    60→      ]);
    61→    } catch {
    62→      const lower = s.url.toLowerCase();
    63→      const fallbackType = lower.includes(".m3u8") || lower.includes("/m3u8") || lower.includes("format=m3u8") ? "m3u8" as const
    64→        : lower.includes(".mp4") || lower.includes(".mkv") ? "mp4" as const
    65→        : "unknown" as const;
    66→      resolved = { url: s.url, type: fallbackType, referer: s.referer };
    67→    }
    68→
    69→    const refererForProxy = resolved.referer || s.referer || s.url;
    70→    let finalUrl: string;
