      })),
      baseUrl
    );

    if (streams.length > 0) {
      setCached("stream", cacheKey, streams);
    }
    return streams;
  } catch (err: any) {
    if (isDebug()) console.error(`[Provider] Stream error:`, err.message);
    return [];
  }
}

